import html

def sanitize_input(text: str) -> str:
    """转义 HTML 特殊字符"""
    if not text:
        return text
    return html.escape(text)

修复代码示例.使用 bleach 清理 HTML:
import bleach

def clean_html(text: str) -> str:
    """清理 HTML 标签，只保留安全标签"""
    allowed_tags = ['b', 'i', 'u', 'em', 'strong']
    return bleach.clean(text, tags=allowed_tags, strip=True)
